              Hello, {currentUser?.full_name?.split(' ')[0]}
            </h1>
            <p className="text-slate-400 font-medium mt-2">
              {isAdminGlobal ? "Voici l'état de santé global du réseau SaaS." : "Gérez vos ventes de tickets et suivez vos gains."}
