import React, { useEffect, useState } from 'react';
import { Tag, Search, Loader2, Pencil, X, Save, AlertCircle, CheckCircle2, DollarSign, Zap, Ticket, AlertTriangle, TrendingUp } from 'lucide-react';
import { db } from '../services/db';

const Profiles: React.FC = () => {
  const [profiles, setProfiles] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [editingProfile, setEditingProfile] = useState<any | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [toast, setToast] = useState<{ type: 'success' | 'error', message: string } | null>(null);

  // Edit Form States
  const [editPrice, setEditPrice] = useState('');
  const [editThreshold, setEditThreshold] = useState('10');
  const [editCost, setEditCost] = useState('0');

  const [currency, setCurrency] = useState('GNF');

  useEffect(() => { fetchProfiles(); }, []);
  const showToast = (type: 'success' | 'error', message: string) => { setToast({ type, message }); setTimeout(() => setToast(null), 3000); };

  const fetchProfiles = async () => {
    try {
      setLoading(true);
      const { data: { user } } = await db.auth.getUser();
      if (!user) return;
      const { data: profile } = await db.from('users').select('tenant_id, tenants(currency)').eq('id', user.id).single();
      // On récupère aussi cost_price et low_stock_threshold
      const { data, error } = await db.from('ticket_profiles').select('*, tickets(count)').eq('tenant_id', profile?.tenant_id).order('name');
      if (error) throw error;
      setProfiles(data || []);
      setCurrency((profile?.tenants as any)?.currency || 'GNF');
    } catch (err: any) { showToast('error', err.message); } finally { setLoading(false); }
  };

  const handleUpdateProfile = async (e: React.FormEvent) => {
    e.preventDefault(); if (!editingProfile) return;
    setIsSubmitting(true);
    try {
      const { error } = await db.from('ticket_profiles').update({ 
        price: Number(editPrice),
        low_stock_threshold: Number(editThreshold),
        cost_price: Number(editCost)
      }).eq('id', editingProfile.id);

      if (error) throw error;
      showToast('success', `Forfait ${editingProfile.name} mis à jour`);
      setEditingProfile(null); fetchProfiles();
    } catch (err: any) { showToast('error', err.message); } finally { setIsSubmitting(false); }
  };

  const filteredProfiles = profiles.filter(p => p.name.toLowerCase().includes(searchTerm.toLowerCase()));

  return (
    <div className="space-y-8 pb-20 animate-in fade-in duration-500">
      {toast && (<div className={`fixed top-6 right-6 z-[60] px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-right-10 border ${toast.type === 'success' ? 'bg-emerald-600 text-white border-emerald-500' : 'bg-red-600 text-white border-red-500'}`}>{toast.type === 'success' ? <CheckCircle2 className="w-5 h-5" /> : <AlertCircle className="w-5 h-5" />}<p className="font-bold text-sm">{toast.message}</p></div>)}

      <header className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div>
          <div className="flex items-center gap-2 text-brand-600 mb-1"><Zap className="w-4 h-4 fill-current" /><span className="text-[10px] font-black uppercase tracking-widest">Catalogue Offres</span></div>
          <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight">Forfaits & Rentabilité</h1>
          <p className="text-slate-400 font-medium text-sm mt-2">Gérez vos prix, vos seuils d'alerte et suivez vos marges.</p>
        </div>
      </header>

      <div className="bg-white rounded-[2.5rem] border border-slate-100 shadow-sm overflow-hidden">
        <div className="p-8 border-b border-slate-50 flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="relative max-w-md w-full group">
            <Search className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300 group-focus-within:text-brand-600 transition-colors" />
            <input type="text" placeholder="Chercher un forfait..." value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className="w-full pl-14 pr-6 py-4 rounded-2xl border border-slate-100 bg-slate-50 focus:bg-white focus:ring-4 focus:ring-brand-50 outline-none font-bold text-slate-700 transition-all" />
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 p-8">
          {loading ? (
            <div className="col-span-full py-20 text-center"><Loader2 className="w-10 h-10 animate-spin mx-auto text-brand-600/20" /></div>
          ) : filteredProfiles.length > 0 ? filteredProfiles.map((p) => {
            const stockCount = p.tickets?.[0]?.count || 0;
            const isLowStock = stockCount <= (p.low_stock_threshold || 10);
            const margin = p.price - (p.cost_price || 0);

            return (
              <div key={p.id} className={`bg-white p-8 rounded-[2.5rem] border-2 transition-all group relative overflow-hidden ${isLowStock ? 'border-red-100 bg-red-50/10' : 'border-slate-50 hover:border-brand-500'}`}>
                {isLowStock && (
                  <div className="absolute top-0 right-0 bg-red-500 text-white px-4 py-1 rounded-bl-2xl flex items-center gap-1.5 animate-pulse">
                    <AlertTriangle className="w-3 h-3" />
                    <span className="text-[9px] font-black uppercase">Stock Critique</span>
                  </div>
                )}

                <div className="flex justify-between items-start mb-6">
                  <div className={`w-12 h-12 rounded-2xl flex items-center justify-center ${isLowStock ? 'bg-red-100 text-red-600' : 'bg-brand-50 text-brand-600'}`}><Tag className="w-6 h-6" /></div>
                  <button onClick={() => { 
                    setEditingProfile(p); 
                    setEditPrice(p.price.toString());
                    setEditThreshold((p.low_stock_threshold || 10).toString());
                    setEditCost((p.cost_price || 0).toString());
                  }} className="p-2.5 bg-white text-slate-300 hover:text-slate-900 rounded-xl shadow-sm border border-slate-100 transition-all"><Pencil className="w-4 h-4" /></button>
                </div>

                <h3 className="text-xl font-black text-slate-900 mb-1">{p.name}</h3>
                <div className="flex items-baseline gap-2 mb-4">
                  <p className="text-2xl font-black text-brand-600">{p.price.toLocaleString()}</p>
                  <span className="text-[10px] uppercase font-bold text-slate-400">{currency}</span>
                </div>

                <div className="space-y-3 pt-4 border-t border-slate-100">
                  <div className="flex justify-between items-center text-[10px] font-bold uppercase tracking-widest text-slate-400">
                    <span>Marge Estimée</span>
                    <span className="text-emerald-600">+{margin.toLocaleString()} {currency}</span>
                  </div>
                  <div className="flex justify-between items-center">
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">En Stock</span>
                    <span className={`text-sm font-black ${isLowStock ? 'text-red-600' : 'text-slate-900'}`}>{stockCount} pcs</span>
                  </div>
                  <div className="h-1.5 w-full bg-slate-100 rounded-full overflow-hidden">
                    <div className={`h-full rounded-full transition-all duration-1000 ${isLowStock ? 'bg-red-500' : 'bg-brand-500'}`} style={{ width: `${Math.min(100, (stockCount / (p.low_stock_threshold * 5 || 50)) * 100)}%` }} />
                  </div>
                </div>
              </div>
            );
          }) : (
            <div className="col-span-full py-20 text-center text-slate-300 font-bold uppercase text-xs">Aucun forfait configuré</div>
          )}
        </div>
      </div>

      {editingProfile && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 animate-in fade-in">
          <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => !isSubmitting && setEditingProfile(null)} />
          <form onSubmit={handleUpdateProfile} className="bg-white w-full max-w-md rounded-[3rem] p-10 relative z-10 animate-in zoom-in-95 shadow-2xl">
            <button type="button" onClick={() => setEditingProfile(null)} className="absolute top-8 right-8 text-slate-300 hover:text-slate-900"><X className="w-6 h-6" /></button>
            <h2 className="text-2xl font-black mb-2 uppercase text-slate-900 tracking-tight">Configuration Experte</h2>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-8">{editingProfile.name}</p>

            <div className="space-y-6">
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Prix de Vente Client ({currency})</label>
                <div className="relative mt-1">
                  <input type="number" required autoFocus value={editPrice} onChange={e => setEditPrice(e.target.value)} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl font-black text-2xl text-brand-600 outline-none focus:bg-white transition-all" />
                  <DollarSign className="absolute right-6 top-1/2 -translate-y-1/2 text-slate-300" />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Seuil Alerte Stock</label>
                  <input type="number" value={editThreshold} onChange={e => setEditThreshold(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-black text-lg outline-none focus:bg-white transition-all" />
                </div>
                <div>
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Coût de Revient</label>
                  <input type="number" value={editCost} onChange={e => setEditCost(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl font-black text-lg outline-none focus:bg-white transition-all" />
                </div>
              </div>

              <div className="bg-emerald-50 p-4 rounded-2xl flex items-center gap-4">
                <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center text-emerald-600 shadow-sm"><TrendingUp className="w-5 h-5" /></div>
                <div>
                  <p className="text-[9px] font-black text-emerald-700 uppercase tracking-widest">Bénéfice Net par ticket</p>
                  <p className="text-lg font-black text-emerald-900">{(Number(editPrice) - Number(editCost)).toLocaleString()} {currency}</p>
                </div>
              </div>
            </div>

            <button type="submit" disabled={isSubmitting} className="w-full mt-10 py-5 bg-slate-900 hover:bg-black text-white rounded-2xl font-black uppercase text-xs tracking-widest flex items-center justify-center gap-2 shadow-xl">
              {isSubmitting ? <Loader2 className="w-5 h-5 animate-spin" /> : <><Save className="w-4 h-4" /> APPLIQUER LA CONFIG</>}
            </button>
          </form>
        </div>
      )}
    </div>
  );
};

export default Profiles;

import React, { useEffect, useState, useCallback } from 'react';
import { 
  Users as UsersIcon, Ticket, Wallet, ShoppingCart, Loader2, RefreshCcw, 
  TrendingUp, ArrowUpRight, ShieldCheck, Building2, Clock, Activity, 
  Globe, MapPin, X, AlertCircle, Smartphone, CheckCircle2, History, 
  Banknote, ArrowDownRight, Zap, ArrowDownLeft, Landmark, AlertTriangle
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { db } from '../services/db';
import { UserRole, TicketStatus } from '../types';

const Dashboard: React.FC = () => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(true);
  const [stats, setStats] = useState({ 
    revenue: 0, 
    sold: 0, 
    stock: 0, 
    users: 0, 
    pendingAgencies: 0, 
    totalAgencies: 0, 
    balance: 0,
    dailyGrowth: 0,
    pendingPayments: 0,
    margin: 0 // Nouveau : Bénéfice net estimé
  });
  const [recentActivities, setRecentActivities] = useState<any[]>([]);
  const [lowStockProfiles, setLowStockProfiles] = useState<any[]>([]);
  const [currentUser, setCurrentUser] = useState<any>(null);
  const [agencyName, setAgencyName] = useState<string>('');
  const [currency, setCurrency] = useState('GNF');

  // Modal States
  const [showDepositModal, setShowDepositModal] = useState(false);
  const [depositAmount, setDepositAmount] = useState('');
  const [depositMethod, setDepositMethod] = useState('CASH');
  const [depositReference, setDepositReference] = useState('');
  const [isSubmittingDeposit, setIsSubmittingDeposit] = useState(false);
  const [toast, setToast] = useState<{ type: 'success' | 'error', message: string } | null>(null);

  const fetchDashboardData = useCallback(async () => {
    try {
      setLoading(true);
      const { data: { user } } = await db.auth.getUser();
      if (!user) return;

      const { data: profile } = await db.from('users').select('*, tenants(name, currency)').eq('id', user.id).maybeSingle();
      if (!profile) return;

      setCurrentUser(profile);
      setAgencyName((profile.tenants as any)?.name || 'Gestion Hotspot');
      setCurrency((profile.tenants as any)?.currency || 'GNF');

      const isAdminGlobal = profile.role === UserRole.ADMIN_GLOBAL;
      const isReseller = profile.role === UserRole.REVENDEUR;
      const tId = profile.tenant_id;

      let stockQuery = db.from('tickets').select('*', { count: 'exact', head: true });
      let soldQuery = db.from('tickets').select('*', { count: 'exact', head: true });
      let revQuery = db.from('sales_history').select('amount_paid, tickets(cost_price)');
      let userQuery = db.from('users').select('*', { count: 'exact', head: true });
      let activityQuery = db.from('accounting_ledger').select('*').limit(8).order('entry_date', { ascending: false });
      let pendingPayQuery = db.from('payments').select('amount').eq('status', 'PENDING');
      let lowStockQuery = db.from('ticket_profiles').select('name, low_stock_threshold, tickets(count)');

      if (isAdminGlobal) {
        // Stats globales...
      } else if (isReseller) {
        stockQuery = stockQuery.eq('assigned_to', user.id).eq('status', TicketStatus.ASSIGNE);
        soldQuery = soldQuery.eq('sold_by', user.id).eq('status', TicketStatus.VENDU);
        revQuery = revQuery.eq('seller_id', user.id);
        activityQuery = activityQuery.eq('user_id', user.id);
        pendingPayQuery = pendingPayQuery.eq('reseller_id', user.id);
      } else {
        stockQuery = stockQuery.eq('tenant_id', tId).eq('status', TicketStatus.NEUF);
        soldQuery = soldQuery.eq('tenant_id', tId).eq('status', TicketStatus.VENDU);
        revQuery = revQuery.eq('tenant_id', tId);
        userQuery = userQuery.eq('tenant_id', tId);
        activityQuery = activityQuery.eq('tenant_id', tId);
        pendingPayQuery = pendingPayQuery.eq('tenant_id', tId);
        lowStockQuery = lowStockQuery.eq('tenant_id', tId);
      }

      const promises = [stockQuery, soldQuery, revQuery, userQuery, activityQuery, pendingPayQuery, lowStockQuery];

      if (isAdminGlobal) {
        promises.push(db.from('tenants').select('*', { count: 'exact', head: true }).eq('subscription_status', 'EN_ATTENTE'));
        promises.push(db.from('tenants').select('*', { count: 'exact', head: true }));
      }

      const results = await Promise.all(promises);

      const revenueData = results[2].data || [];
      const totalRevenue = revenueData.reduce((acc: number, curr: any) => acc + Number(curr.amount_paid), 0);
      const totalCost = revenueData.reduce((acc: number, curr: any) => acc + Number((curr.tickets as any)?.cost_price || 0), 0);
      const pendingAmt = (results[5].data || []).reduce((acc: number, curr: any) => acc + Number(curr.amount), 0);

      // Filtrage des stocks bas
      const lowStocks = (results[6].data || []).filter((p: any) => {
          const count = p.tickets?.[0]?.count || 0;
          return count <= (p.low_stock_threshold || 10);
      });
      setLowStockProfiles(lowStocks);

      setStats({
        revenue: totalRevenue,
        sold: results[1].count || 0,
        stock: results[0].count || 0,
        users: results[3].count || 0,
        pendingAgencies: isAdminGlobal ? (results[7]?.count || 0) : 0,
        totalAgencies: isAdminGlobal ? (results[8]?.count || 0) : 0,
        balance: profile.balance || 0,
        dailyGrowth: 0,
        pendingPayments: pendingAmt,
        margin: totalRevenue - totalCost
      });

      setRecentActivities(results[4].data || []);

    } catch (err) { 
      console.error("Dashboard Fetch Error:", err); 
    } finally { 
      setLoading(false); 
    }
  }, []);

  useEffect(() => { fetchDashboardData(); }, [fetchDashboardData]);

  const handleSubmitVersement = async (e: React.FormEvent) => {
      e.preventDefault();
      setIsSubmittingDeposit(true);
      try {
          const { error } = await db.from('payments').insert({
              tenant_id: currentUser?.tenant_id,
              reseller_id: currentUser?.id,
              amount: Number(depositAmount),
              payment_method: depositMethod,
              phone_number: depositReference || 'Versement Main à Main',
              status: 'PENDING',
              created_by: currentUser?.id
          });
          if(error) throw error;
          setToast({ type: 'success', message: "Versement déclaré avec succès." });
          setShowDepositModal(false);
          setDepositAmount('');
          setDepositReference('');
          fetchDashboardData();
      } catch(err: any) {
          setToast({ type: 'error', message: err.message });
      } finally {
          setIsSubmittingDeposit(false);
      }
  };

  if (loading) return <div className="h-screen flex items-center justify-center"><Loader2 className="animate-spin text-brand-600" /></div>;

  const isReseller = currentUser?.role === UserRole.REVENDEUR;

  return (
    <div className="space-y-6 md:space-y-10 animate-in fade-in duration-700">
      {toast && (
        <div className={`fixed top-6 right-6 z-[100] px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-right border ${toast.type === 'success' ? 'bg-emerald-600 text-white' : 'bg-red-600 text-white'}`}>
          <CheckCircle2 className="w-5 h-5 shrink-0" />
          <p className="font-bold text-sm">{toast.message}</p>
        </div>
      )}

      {/* ALERTES STOCK BAS */}
      {lowStockProfiles.length > 0 && !isReseller && (
          <div className="bg-red-50 border-2 border-red-100 p-6 rounded-[2.5rem] flex flex-col md:flex-row items-center justify-between gap-4 animate-pulse">
              <div className="flex items-center gap-4">
                  <div className="w-12 h-12 bg-red-600 text-white rounded-2xl flex items-center justify-center shadow-lg shadow-red-200">
                      <AlertTriangle className="w-6 h-6" />
                  </div>
                  <div>
                      <h4 className="font-black text-red-900 uppercase text-xs tracking-widest">Alerte de Stock Critique</h4>
                      <p className="text-red-700 text-sm font-medium">Les forfaits <strong>{lowStockProfiles.map(p => p.name).join(', ')}</strong> sont presque épuisés.</p>
                  </div>
              </div>
              <button onClick={() => navigate('/import')} className="bg-red-600 text-white px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-red-700 transition-all">RECHARGER MAINTENANT</button>
          </div>
      )}

      {/* HEADER */}
      <section className="flex flex-col lg:flex-row lg:items-center justify-between gap-6 bg-white p-8 md:p-12 rounded-[2.5rem] md:rounded-[4rem] border border-slate-100 shadow-sm relative overflow-hidden group">
        <div className="absolute top-0 right-0 w-80 h-80 bg-brand-500 rounded-full blur-[120px] opacity-[0.03] -mr-20 -mt-20"></div>
        <div className="relative z-10 flex flex-col md:flex-row md:items-center gap-6">
          <div className="w-20 h-20 bg-slate-900 rounded-[2rem] flex items-center justify-center text-white shadow-2xl">
            {isReseller ? <Wallet className="w-10 h-10" /> : <Building2 className="w-10 h-10" />}
          </div>
          <div>
            <div className="flex flex-wrap items-center gap-2 mb-2">
              <span className="bg-slate-100 text-slate-600 px-3 py-1 rounded-lg text-[10px] font-black uppercase tracking-widest">{agencyName}</span>
              {isReseller && <span className="bg-indigo-100 text-indigo-700 px-2 py-0.5 rounded-lg text-[10px] font-black uppercase tracking-widest">Compte Revendeur</span>}
            </div>
            <h1 className="text-3xl md:text-5xl font-black text-slate-900 tracking-tighter leading-none">Hello, {currentUser?.full_name?.split(' ')[0]}</h1>
          </div>
        </div>

        <div className="flex items-center gap-3 relative z-10">
          {!isReseller && !currentUser?.role.includes('ADMIN_GLOBAL') && (
            <div className="bg-emerald-50 px-6 py-4 rounded-3xl border border-emerald-100 hidden md:block">
                <p className="text-[9px] font-black text-emerald-600 uppercase tracking-widest mb-1">Bénéfice Estimé</p>
                <p className="text-xl font-black text-emerald-900">+{stats.margin.toLocaleString()} <span className="text-[10px]">{currency}</span></p>
            </div>
          )}
          <button onClick={() => navigate('/sales')} className="bg-brand-600 hover:bg-brand-700 text-white px-8 py-5 rounded-[2rem] font-black text-xs uppercase tracking-widest flex items-center justify-center gap-3 shadow-xl transition-all active:scale-95 group">
            <ShoppingCart className="w-5 h-5 group-hover:-translate-y-1 transition-transform" /> VENDRE TICKETS
          </button>
        </div>
      </section>

      {/* KPI GRID */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <KpiCard 
          label={isReseller ? "Recettes de Vente" : "Chiffre d'Affaires"}
          value={stats.revenue.toLocaleString()}
          unit={currency}
          icon={<TrendingUp />}
          color="text-indigo-600"
          bg="bg-indigo-50"
        />

        <div className="bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm flex flex-col justify-between group hover:shadow-xl transition-all">
          <div className="flex justify-between items-start mb-6">
            <div className={`w-14 h-14 rounded-2xl flex items-center justify-center shadow-inner ${stats.balance < 10000 ? 'bg-red-50 text-red-500' : 'bg-emerald-50 text-emerald-600'}`}>
              <Wallet className="w-7 h-7" />
            </div>
            {isReseller && (
              <button onClick={() => setShowDepositModal(true)} className="px-4 py-2 bg-slate-900 text-white rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-black transition-all shadow-lg">
                VERSER CASH
              </button>
            )}
          </div>
          <div>
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">{isReseller ? "Mon Crédit Disponible" : "Solde Trésorerie"}</p>
            <div className="flex items-baseline gap-1.5">
              <h3 className={`text-3xl font-black ${stats.balance < 0 ? 'text-red-600' : 'text-slate-900'}`}>{stats.balance.toLocaleString()}</h3>
              <span className="text-[10px] font-bold text-slate-400 uppercase">{currency}</span>
            </div>
          </div>
        </div>

        <KpiCard 
          label="Versements à Valider"
          value={stats.pendingPayments.toLocaleString()}
          unit={currency}
          icon={<Clock />}
          color="text-orange-600"
          bg="bg-orange-50"
          onClick={isReseller ? undefined : () => navigate('/resellers')}
        />

        <KpiCard 
          label={isReseller ? "Mes Vouchers" : "Stock Global"}
          value={stats.stock}
          unit="Unités"
          icon={<Ticket />}
          color={lowStockProfiles.length > 0 ? "text-red-600" : "text-slate-600"}
          bg={lowStockProfiles.length > 0 ? "bg-red-50" : "bg-slate-50"}
          onClick={() => navigate('/stock')}
        />
      </div>

      {/* FOOTER DASHBOARD */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden min-h-[400px]">
          <div className="px-10 py-8 border-b border-slate-50 flex items-center justify-between">
            <h3 className="font-black text-slate-900 text-lg uppercase tracking-tight">Journal d'Activité</h3>
            <button onClick={() => navigate('/history')} className="text-[10px] font-black text-brand-600 uppercase tracking-widest">Voir complet</button>
          </div>
          <div className="divide-y divide-slate-50">
            {recentActivities.map((activity, i) => (
              <div key={i} className="px-10 py-6 flex items-center justify-between hover:bg-slate-50 transition-colors">
                <div className="flex items-center gap-5">
                  <div className={`w-12 h-12 rounded-xl flex items-center justify-center ${activity.entry_type === 'VENTE' ? 'bg-indigo-50 text-indigo-600' : 'bg-emerald-50 text-emerald-600'}`}>
                    {activity.entry_type === 'VENTE' ? <ShoppingCart className="w-5 h-5" /> : <Banknote className="w-5 h-5" />}
                  </div>
                  <div>
                    <p className="font-black text-slate-900 text-sm">{activity.description}</p>
                    <p className="text-[10px] font-bold text-slate-400 uppercase">{new Date(activity.entry_date).toLocaleDateString()} • {activity.party_name}</p>
                  </div>
                </div>
                <div className="text-right">
                  <p className={`font-black text-lg ${activity.entry_type === 'VENTE' ? 'text-slate-900' : 'text-emerald-600'}`}>
                    {activity.entry_type === 'VENTE' ? '-' : '+'}{Number(activity.amount).toLocaleString()}
                  </p>
                  <p className="text-[9px] font-bold text-slate-400 uppercase">{currency}</p>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="space-y-6">
            <div className="bg-slate-900 rounded-[3rem] p-10 text-white shadow-2xl relative overflow-hidden">
                <div className="absolute top-0 right-0 w-32 h-32 bg-brand-500 rounded-full blur-[60px] opacity-20"></div>
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-6">Performance Agence</h4>
                <div className="space-y-6 mb-8">
                    <div className="flex justify-between items-center">
                        <span className="text-xs font-bold text-slate-400">Taux de marge</span>
                        <span className="text-xs font-black text-emerald-400">{stats.revenue > 0 ? Math.round((stats.margin / stats.revenue) * 100) : 0}%</span>
                    </div>
                    <div className="h-2 w-full bg-white/10 rounded-full overflow-hidden">
                        <div className="h-full bg-emerald-500 rounded-full" style={{ width: `${stats.revenue > 0 ? Math.round((stats.margin / stats.revenue) * 100) : 0}%` }}></div>
                    </div>
                </div>
                <button onClick={() => navigate('/accounting')} className="w-full py-4 bg-brand-600 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl shadow-brand-900/40 hover:bg-brand-500 transition-all">DÉTAILS COMPTABLES</button>
            </div>
        </div>
      </div>

      {/* VERSEMENT MODAL */}
      {showDepositModal && (
          <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 animate-in fade-in">
              <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm" onClick={() => setShowDepositModal(false)} />
              <form onSubmit={handleSubmitVersement} className="bg-white w-full max-w-sm rounded-[3rem] p-10 relative z-10 animate-in zoom-in-95 shadow-2xl">
                  <button type="button" onClick={() => setShowDepositModal(false)} className="absolute top-8 right-8 text-slate-300 hover:text-slate-900 transition-colors"><X className="w-6 h-6" /></button>
                  <h2 className="text-2xl font-black mb-8 uppercase text-center text-slate-900 tracking-tight">Déclarer Versement</h2>
                  <div className="space-y-6">
                      <div>
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Montant ({currency})</label>
                          <input type="number" required placeholder="ex: 150000" value={depositAmount} onChange={e => setDepositAmount(e.target.value)} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl font-black text-xl outline-none focus:bg-white focus:ring-4 focus:ring-brand-50 transition-all" />
                      </div>
                      <div>
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Méthode</label>
                          <select value={depositMethod} onChange={e => setDepositMethod(e.target.value)} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl font-black outline-none appearance-none focus:bg-white focus:ring-4 focus:ring-brand-50 transition-all cursor-pointer">
                              <option value="CASH">Espèces</option>
                              <option value="MOMO">Mobile Money</option>
                              <option value="OM">Orange Money</option>
                          </select>
                      </div>
                      <div>
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Preuve / Référence</label>
                          <input type="text" placeholder="Qui a reçu le cash ?" value={depositReference} onChange={e => setDepositReference(e.target.value)} className="w-full p-5 bg-slate-50 border border-slate-100 rounded-2xl font-black text-lg outline-none focus:bg-white transition-all" />
                      </div>
                  </div>
                  <button type="submit" disabled={isSubmittingDeposit} className="w-full mt-10 py-5 bg-emerald-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest flex items-center justify-center gap-2 shadow-xl hover:bg-emerald-700 transition-all">
                      {isSubmittingDeposit ? <Loader2 className="w-5 h-5 animate-spin" /> : "ENVOYER LA DÉCLARATION"}
                  </button>
              </form>
          </div>
      )}
    </div>
  );
};

const KpiCard = ({ label, value, unit, icon, color, bg, onClick }: any) => (
  <div 
    onClick={onClick} 
    className={`bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm hover:shadow-xl transition-all duration-300 group ${onClick ? 'cursor-pointer' : ''}`}
  >
    <div className={`w-14 h-14 ${bg} ${color} rounded-2xl flex items-center justify-center shadow-inner group-hover:scale-110 transition-transform mb-6`}>
      {React.cloneElement(icon, { className: "w-7 h-7" })}
    </div>
    <div>
      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 truncate">{label}</p>
      <div className="flex items-baseline gap-1.5 flex-wrap">
        <h3 className={`text-3xl font-black text-slate-900 tracking-tighter`}>{value}</h3>
        <span className="text-[10px] font-bold text-slate-400 uppercase">{unit}</span>
      </div>
    </div>
  </div>
);

export default Dashboard;

import React, { useState, useEffect, useCallback } from 'react';
import { Search, CloudUpload, Trash2, Loader2, AlertCircle, AlertTriangle, CheckCircle2, Building2, UserX, Ticket, Users, Filter, X } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { db } from '../services/db';
import { UserRole, TicketStatus } from '../types';

const Stock: React.FC = () => {
  const navigate = useNavigate();
  const [filter, setFilter] = useState<'TOUS' | 'NEUF' | 'VENDU' | 'ASSIGNÉ'>('TOUS');
  const [agencyFilter, setAgencyFilter] = useState<string>('ALL');
  const [resellerFilter, setResellerFilter] = useState<string>('ALL');
  const [search, setSearch] = useState('');

  const [tickets, setTickets] = useState<any[]>([]);
  const [agencies, setAgencies] = useState<any[]>([]);
  const [resellers, setResellers] = useState<any[]>([]);

  const [loading, setLoading] = useState(true);
  const [currentUser, setCurrentUser] = useState<any>(null);
  const [ticketToDelete, setTicketToDelete] = useState<any | null>(null);
  const [isDeleting, setIsDeleting] = useState(false);
  const [ticketToUnassign, setTicketToUnassign] = useState<any | null>(null);
  const [isUnassigning, setIsUnassigning] = useState(false);
  const [toast, setToast] = useState<{ type: 'success' | 'error', message: string } | null>(null);
  const [currency, setCurrency] = useState('GNF');

  const showToast = useCallback((type: 'success' | 'error', message: string) => { 
    setToast({ type, message }); 
    setTimeout(() => setToast(null), 3000); 
  }, []);

  const fetchInitialData = useCallback(async () => {
    try {
      const { data: { user } } = await db.auth.getUser();
      if (user) {
        const { data: userData } = await db.from('users').select('role, tenant_id, id, tenants(currency)').eq('id', user.id).single();
        if (userData) {
          setCurrentUser(userData);
          setCurrency((userData.tenants as any)?.currency || 'GNF');

          if (userData.role === UserRole.ADMIN_GLOBAL) {
            const { data: tData } = await db.from('tenants').select('id, name').order('name');
            setAgencies(tData || []);
          }

          // Charger la liste des revendeurs pour le filtre (si admin ou gestionnaire)
          if (userData.role !== UserRole.REVENDEUR) {
              let resQuery = db.from('users').select('id, full_name').eq('role', UserRole.REVENDEUR).eq('is_active', true);
              if (userData.role !== UserRole.ADMIN_GLOBAL) {
                  resQuery = resQuery.eq('tenant_id', userData.tenant_id);
              }
              const { data: resellersData } = await resQuery.order('full_name');
              setResellers(resellersData || []);
          }
        }
      }
    } catch (err) { console.error(err); }
  }, []);

  const fetchStock = useCallback(async () => {
    if (!currentUser) return;
    try {
      setLoading(true);
      let query = db.from('tickets')
        .select(`id, username, password, status, imported_at, assigned_to, tenants(name), ticket_profiles(name, price), users!tickets_assigned_to_fkey(full_name)`)
        .order('imported_at', { ascending: false });

      const isReseller = currentUser.role === UserRole.REVENDEUR;

      if (currentUser.role === UserRole.ADMIN_GLOBAL) { 
        if (agencyFilter !== 'ALL') query = query.eq('tenant_id', agencyFilter); 
      } else { 
        query = query.eq('tenant_id', currentUser.tenant_id); 
      }

      // Filtre Revendeur (Prioritaire sur le statut si sélectionné)
      if (resellerFilter !== 'ALL') {
          query = query.eq('assigned_to', resellerFilter);
      } else if (isReseller) {
         query = query.eq('assigned_to', currentUser.id);
      }

      // Filtre Statut
      if (filter !== 'TOUS') {
          if (isReseller && filter === 'NEUF') {
              query = query.eq('status', TicketStatus.ASSIGNE);
          } else if (filter === 'ASSIGNÉ') {
              query = query.eq('status', TicketStatus.ASSIGNE);
          } else {
              query = query.eq('status', filter);
          }
      }

      if (search) query = query.ilike('username', `%${search}%`);

      const { data, error: tError } = await query.limit(300);
      if (tError) throw tError;
      setTickets(data || []);
    } catch (err: any) { showToast('error', err.message); } finally { setLoading(false); }
  }, [currentUser, filter, search, agencyFilter, resellerFilter, showToast]);

  useEffect(() => { fetchInitialData(); }, [fetchInitialData]);
  useEffect(() => { fetchStock(); }, [fetchStock]);

  const handleVerifyDelete = (ticket: any) => { 
    if (currentUser?.role === UserRole.REVENDEUR) { showToast('error', "Action refusée."); return; } 
    if (ticket.status !== TicketStatus.NEUF) { showToast('error', "Impossible de supprimer un ticket vendu ou assigné."); return; } 
    setTicketToDelete(ticket); 
  };

  const performDelete = async () => { 
    if (!ticketToDelete) return; 
    setIsDeleting(true); 
    try { 
        const { error: dError } = await db.from('tickets').delete().eq('id', ticketToDelete.id); 
        if (dError) throw dError; 
        setTickets(prev => prev.filter(t => t.id !== ticketToDelete.id)); 
        showToast('success', `Ticket supprimé.`); 
        setTicketToDelete(null); 
    } catch (err: any) { showToast('error', err.message); } finally { setIsDeleting(false); } 
  };

  const handleVerifyUnassign = (ticket: any) => {
    if (currentUser?.role === UserRole.REVENDEUR) return;
    setTicketToUnassign(ticket);
  };

  const performUnassign = async () => {
    if (!ticketToUnassign) return;
    setIsUnassigning(true);
    try {
        const { error } = await db.from('tickets').update({ status: TicketStatus.NEUF, assigned_to: null }).eq('id', ticketToUnassign.id);
        if (error) throw error;
        setTickets(prev => prev.map(t => {
            if (t.id === ticketToUnassign.id) return { ...t, status: TicketStatus.NEUF, assigned_to: null, users: null };
            return t;
        }));
        showToast('success', "Ticket retiré du revendeur."); setTicketToUnassign(null);
    } catch (err: any) { showToast('error', err.message); } finally { setIsUnassigning(false); }
  };

  const isReseller = currentUser?.role === UserRole.REVENDEUR;

  return (
    <div className="space-y-6 md:space-y-8 font-sans pb-24 animate-in fade-in duration-500 relative">
      {toast && (<div className={`fixed top-6 right-6 z-[60] px-6 py-4 rounded-2xl shadow-2xl flex items-center gap-3 animate-in slide-in-from-right-10 border ${toast.type === 'success' ? 'bg-emerald-600 text-white border-emerald-500' : 'bg-red-600 text-white border-red-500'}`}>{toast.type === 'success' ? <CheckCircle2 className="w-5 h-5" /> : <AlertCircle className="w-5 h-5" />}<p className="font-bold text-sm">{toast.message}</p></div>)}

      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-6">
          <div>
              <span className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.2em] mb-1 block">{currentUser?.role === UserRole.ADMIN_GLOBAL ? 'SUPERVISION GLOBALE DES STOCKS' : (isReseller ? 'MON STOCK PERSONNEL' : 'INVENTAIRE AGENCE')}</span>
              <h1 className="text-3xl md:text-4xl font-black text-[#1e293b] tracking-tight">Gestion Stock</h1>
          </div>
          {currentUser?.role === UserRole.GESTIONNAIRE_WIFI_ZONE && (
              <button onClick={() => navigate('/import')} className="bg-slate-900 text-white px-6 py-4 rounded-2xl font-black text-xs tracking-widest uppercase shadow-xl flex items-center justify-center gap-3 hover:bg-black transition-all active:scale-95 w-full lg:w-auto">
                  <CloudUpload className="w-4 h-4" /> IMPORTER CSV
              </button>
          )}
      </div>

      <div className="bg-white rounded-[2rem] md:rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden">
          <div className="p-6 md:p-8 space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
                  {/* RECHERCHE */}
                  <div className="relative group lg:col-span-2">
                      <Search className="absolute left-6 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-300 group-focus-within:text-indigo-500 transition-colors" />
                      <input type="text" placeholder="Rechercher par code..." value={search} onChange={(e) => setSearch(e.target.value)} className="w-full pl-14 pr-8 py-4 rounded-2xl border border-slate-100 bg-slate-50/30 focus:bg-white focus:ring-4 focus:ring-indigo-50 outline-none font-bold text-slate-600 transition-all text-sm md:text-base" />
                  </div>

                  {/* FILTRE AGENCE (GLOBAL ADMIN SEULEMENT) */}
                  {currentUser?.role === UserRole.ADMIN_GLOBAL && (
                      <div className="relative w-full">
                          <Building2 className="absolute left-5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300" />
                          <select value={agencyFilter} onChange={(e) => setAgencyFilter(e.target.value)} className="w-full pl-12 pr-10 py-4 rounded-2xl border border-slate-100 bg-slate-50 font-bold text-slate-600 appearance-none outline-none focus:ring-4 focus:ring-indigo-50 transition-all text-sm"><option value="ALL">Toutes les agences</option>{agencies.map(a => <option key={a.id} value={a.id}>{a.name}</option>)}</select>
                          <Filter className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300 pointer-events-none" />
                      </div>
                  )}

                  {/* FILTRE REVENDEUR (ADMIN & GESTIONNAIRE) */}
                  {!isReseller && (
                      <div className="relative w-full">
                          <Users className="absolute left-5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300" />
                          <select value={resellerFilter} onChange={(e) => setResellerFilter(e.target.value)} className="w-full pl-12 pr-10 py-4 rounded-2xl border border-slate-100 bg-slate-50 font-bold text-slate-600 appearance-none outline-none focus:ring-4 focus:ring-indigo-50 transition-all text-sm">
                              <option value="ALL">Tous les revendeurs</option>
                              {resellers.map(r => <option key={r.id} value={r.id}>{r.full_name}</option>)}
                          </select>
                          <Filter className="absolute right-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-300 pointer-events-none" />
                      </div>
                  )}
              </div>

              <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
                  {(['TOUS', 'NEUF', 'ASSIGNÉ', 'VENDU'] as const).map((f) => (
                      <button key={f} onClick={() => setFilter(f)} className={`px-5 py-2.5 rounded-xl font-black text-[10px] tracking-widest uppercase transition-all whitespace-nowrap ${filter === f ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' : 'bg-white border border-slate-100 text-slate-400 hover:text-slate-600'}`}>
                          {f === 'NEUF' ? 'STOCK DISPO (AGENCE)' : f === 'ASSIGNÉ' ? 'CHEZ REVENDEURS' : f}
                      </button>
                  ))}
                  {(resellerFilter !== 'ALL' || search || agencyFilter !== 'ALL') && (
                      <button onClick={() => { setResellerFilter('ALL'); setSearch(''); setAgencyFilter('ALL'); setFilter('TOUS'); }} className="px-5 py-2.5 rounded-xl font-black text-[10px] tracking-widest uppercase bg-red-50 text-red-500 hover:bg-red-100 transition-all flex items-center gap-2">
                          <X className="w-3 h-3" /> RÉINITIALISER
                      </button>
                  )}
              </div>
          </div>

          <div className="overflow-x-auto">
              <table className="w-full text-left border-collapse min-w-[800px]">
                  <thead>
                      <tr className="border-y border-slate-50 bg-slate-50/30 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                          {!isReseller && <th className="px-6 md:px-8 py-4">CODE</th>}
